112	// executeOnService dispatches against a pre-built svc using the durable
113	// knobs from rcfg and per-invocation plumbing from runtime, then records
114	// one session-index row. It is the inlined replacement for the retired
115	// RunViaServiceWith helper and is shared with dispatchViaResolvedConfig.
116	func executeOnService(ctx context.Context, svc agentlib.FizeauService, workDir string, rcfg config.ResolvedConfig, runtime AgentRunRuntime) (*Result, error) {
117		if svc == nil {
118			return nil, fmt.Errorf("agent: nil service")
119		}
120		if ctx == nil {
121			ctx = context.Background()
122		}
123	
124		promptText := runtime.Prompt
125		if runtime.PromptFile != "" {
126			data, err := readPromptFileBounded(runtime.PromptFile)
127			if err != nil {
128				return nil, fmt.Errorf("agent: read prompt file: %w", err)
129			}
130			promptText = string(data)
131		}
132		if promptText == "" {
133			return nil, fmt.Errorf("agent: prompt is required")
134		}
135	
136		wd := runtime.WorkDir
137		if wd == "" {
138			wd = workDir
139		}
140		if wd == "" {
141			wd, _ = os.Getwd()
142		}
143	
144		idle := rcfg.Timeout()
145		if idle <= 0 {
146			idle = time.Duration(DefaultTimeoutMS) * time.Millisecond
147		}
148		wall := rcfg.WallClock()
149		if wall <= 0 {
150			wall = time.Duration(DefaultWallClockMS) * time.Millisecond
151		}
152	
153		sessionLogDir := runtime.SessionLogDirOverride
154		if sessionLogDir == "" {
155			sessionLogDir = rcfg.SessionLogDir()
156		}
157		if sessionLogDir == "" {
158			sessionLogDir = ResolveLogDir(workDir, "")
159		}
160	
161		pt := rcfg.Passthrough()
162	
163		harness := runtime.HarnessOverride
164		if harness == "" {
165			harness = pt.Harness
166		}
167	
168		model := runtime.ModelOverride
169		if model == "" {
170			model = pt.Model
171		}
172	
173		profile := runtime.ProfileOverride
174		if profile == "" {
175			profile = rcfg.Profile()
176		}
177	
178		permissions := runtime.PermissionsOverride
179		if permissions == "" {
180			permissions = rcfg.Permissions()
181		}
182	
183		providerTimeout := ResolveProviderRequestTimeout(workDir, pt.Provider, model, rcfg.ProviderRequestTimeout())
184	
185		minPower := rcfg.MinPower()
186		if runtime.MinPowerOverride > 0 {
187			minPower = runtime.MinPowerOverride
188		}
189		maxPower := rcfg.MaxPower()
190		if runtime.ClearMaxPower {
191			maxPower = 0
192		}
193		if minPower > 0 && maxPower > 0 && minPower >= maxPower {
194			return nil, fmt.Errorf("agent: invalid power bounds: min_power=%d must be less than max_power=%d", minPower, maxPower)
195		}
196	
197		req := agentlib.ServiceExecuteRequest{
198			Prompt:          promptText,
199			Model:           model,
200			Profile:         profile,
201			Provider:        pt.Provider,
202			Harness:         harness,
203			ModelRef:        rcfg.ModelRef(),
204			Reasoning:       agentlib.Reasoning(rcfg.Effort()),
205			Permissions:     permissions,
206			WorkDir:         wd,
207			Timeout:         wall,
208			IdleTimeout:     idle,
209			ProviderTimeout: providerTimeout,
210			SessionLogDir:   sessionLogDir,
211			Metadata:        runtime.Correlation,
212			Role:            runtime.Role,
213			CorrelationID:   runtime.CorrelationID,
214			MinPower:        minPower,
215			MaxPower:        maxPower,
216		}
217	
218		cancelCtx, cancel := context.WithCancel(ctx)
219		defer cancel()
220	
221		start := time.Now().UTC()
222		events, err := svc.Execute(cancelCtx, req)
223		if err != nil {
224			return nil, fmt.Errorf("agent: execute: %w", err)
225		}
226	
227		final, routing, _ := drainServiceEventsWithWriter(events, runtime.Output)
228		finishedAt := time.Now().UTC()
229		elapsed := finishedAt.Sub(start)
230	
231		result := &Result{
232			Harness:    harness,
233			Model:      model,
234			DurationMS: int(elapsed.Milliseconds()),
235		}
236		if routing != nil {
237			result.Provider = routing.Provider
238			if routing.Model != "" {
239				result.Model = routing.Model
240			}
241			if routing.Harness != "" {
242				result.Harness = routing.Harness
243			}
244			if power, speed, cost, source := selectedRoutingCandidateMetrics(routing); power > 0 || speed > 0 || cost > 0 || source != "" {
245				result.PredictedPower = power
246				result.PredictedSpeedTPS = speed
247				result.PredictedCostUSDPer1kTokens = cost
248				result.PredictedCostSource = source
249			}
250		}
251		if final != nil {
252			// Normalized final text from the upstream harness (agent-32e8ff5e);
253			// reviewer verdict extraction now parses this instead of raw stream
254			// frames (ddx-7bc0c8d5).
255			result.Output = final.FinalText
256			if final.Usage != nil {
257				// v0.9.1: Usage fields became *int (nullable).
258				if final.Usage.InputTokens != nil {
259					result.InputTokens = *final.Usage.InputTokens
260				}
261				if final.Usage.OutputTokens != nil {
262					result.OutputTokens = *final.Usage.OutputTokens
263				}
264				if final.Usage.TotalTokens != nil {
265					result.Tokens = *final.Usage.TotalTokens
266				}
267			}
268			if final.CostUSD > 0 {
269				result.CostUSD = final.CostUSD
270			}
271			result.ExitCode = final.ExitCode
272			result.Error = final.Error
273			if final.RoutingActual != nil {
274				if result.Provider == "" {
275					result.Provider = final.RoutingActual.Provider
276				}
277				if final.RoutingActual.Model != "" {
278					result.Model = final.RoutingActual.Model
279				}
280				if final.RoutingActual.Harness != "" {
281					result.Harness = final.RoutingActual.Harness
282				}
283				if final.RoutingActual.Power > 0 {
284					result.ActualPower = final.RoutingActual.Power
285				}
286			}
287			if final.SessionLogPath != "" {
288				result.AgentSessionID = final.SessionLogPath
289			}
290		}
291		result.Error = appendProviderTimeoutHint(result.Error, providerTimeout)
292		entry := SessionIndexEntryFromResult(workDir, SessionIndexInputs{
293			Harness:     harness,
294			Model:       model,
295			Provider:    pt.Provider,
296			Effort:      rcfg.Effort(),
297			Correlation: runtime.Correlation,
298		}, result, start, finishedAt)
299		_ = AppendSessionIndex(ResolveLogDir(workDir, ""), entry, finishedAt)
300		return result, nil
301	}
