303	// CapabilitiesViaService returns HarnessCapabilities for the named harness by
304	// querying the service's ListHarnesses and (best-effort) the harness registry.
305	// It is the production replacement for Runner.Capabilities.
306	func CapabilitiesViaService(ctx context.Context, workDir, harnessName string) (*HarnessCapabilities, error) {
307		if ctx == nil {
308			ctx = context.Background()
309		}
310		svc, err := NewServiceFromWorkDir(workDir)
311		if err != nil {
312			return nil, fmt.Errorf("agent: build service: %w", err)
313		}
314		infos, err := svc.ListHarnesses(ctx)
315		if err != nil {
316			return nil, fmt.Errorf("agent: list harnesses: %w", err)
317		}
318		var info *agentlib.HarnessInfo
319		for i := range infos {
320			if infos[i].Name == harnessName {
321				info = &infos[i]
322				break
323			}
324		}
325		if info == nil {
326			return nil, fmt.Errorf("agent: unknown harness: %s", harnessName)
327		}
328	
329		// Pull binary and reasoning-level metadata from the local registry — the
330		// service does not expose these directly today.
331		registry := newHarnessRegistry()
332		harness, _ := registry.Get(harnessName)
333	
334		caps := &HarnessCapabilities{
335			Harness:             info.Name,
336			Available:           info.Available,
337			Binary:              harness.Binary,
338			Path:                info.Path,
339			Surface:             harness.Surface,
340			CostClass:           info.CostClass,
341			IsLocal:             info.IsLocal,
342			ExactPinSupport:     info.ExactPinSupport,
343			SupportsEffort:      len(info.SupportedReasoning) > 0 || harness.EffortFlag != "",
344			SupportsPermissions: len(info.SupportedPermissions) > 0 || len(harness.PermissionArgs) > 0,
345		}
346		if len(info.SupportedReasoning) > 0 {
347			caps.ReasoningLevels = append([]string{}, info.SupportedReasoning...)
348		} else if len(harness.ReasoningLevels) > 0 {
349			caps.ReasoningLevels = append([]string{}, harness.ReasoningLevels...)
350		}
351	
352		if harness.DefaultModel != "" {
353			caps.Model = harness.DefaultModel
354			caps.Models = []string{harness.DefaultModel}
355		}
356	
357		return caps, nil
358	}
