360	// TestProviderConnectivityViaService runs a HealthCheck against the named
361	// harness and translates the result into a ProviderStatus. It is the
362	// production replacement for Runner.TestProviderConnectivity.
363	func TestProviderConnectivityViaService(ctx context.Context, workDir, harnessName string, timeout time.Duration) ProviderStatus {
364		status := ProviderStatus{Reachable: false}
365		if ctx == nil {
366			ctx = context.Background()
367		}
368		if harnessName == "virtual" || harnessName == "agent" {
369			status.Reachable = true
370			status.CreditsOK = true
371			return status
372		}
373		svc, err := NewServiceFromWorkDir(workDir)
374		if err != nil {
375			status.Error = err.Error()
376			return status
377		}
378		if timeout > 0 {
379			var cancel context.CancelFunc
380			ctx, cancel = context.WithTimeout(ctx, timeout)
381			defer cancel()
382		}
383		if err := svc.HealthCheck(ctx, agentlib.HealthTarget{Type: "harness", Name: harnessName}); err != nil {
384			errStr := strings.ToLower(err.Error())
385			status.Error = err.Error()
386			if strings.Contains(errStr, "429") || strings.Contains(errStr, "quota") ||
387				strings.Contains(errStr, "credit") || strings.Contains(errStr, "insufficient") {
388				status.CreditsOK = false
389			}
390			return status
391		}
392		status.Reachable = true
393		status.CreditsOK = true
394		return status
395	}
