397	// ValidateForExecuteLoopViaService is the production replacement for
398	// Runner.ValidateForExecuteLoop. When harness is empty it is a no-op (routing
399	// will pick at claim time). When harness is specified it confirms the harness
400	// exists in the service registry and (when model is set) attempts a
401	// ResolveRoute pre-flight.
402	func ValidateForExecuteLoopViaService(ctx context.Context, workDir, harnessName, model, provider, modelRef string) error {
403		if harnessName == "" {
404			return nil
405		}
406		if ctx == nil {
407			ctx = context.Background()
408		}
409		svc, err := NewServiceFromWorkDir(workDir)
410		if err != nil {
411			return fmt.Errorf("agent: build service: %w", err)
412		}
413		infos, err := svc.ListHarnesses(ctx)
414		if err != nil {
415			return fmt.Errorf("agent: list harnesses: %w", err)
416		}
417		found := false
418		for _, info := range infos {
419			if info.Name == harnessName {
420				found = true
421				if !info.Available {
422					return fmt.Errorf("agent: harness %s not available", harnessName)
423				}
424				break
425			}
426		}
427		if !found {
428			return fmt.Errorf("agent: unknown harness: %s", harnessName)
429		}
430	
431		// Pre-flight orphan-model check via ResolveRoute. Only meaningful when a
432		// model is provided and provider/model-ref are not set.
433		if model != "" && provider == "" && modelRef == "" && harnessName == "agent" {
434			if _, err := svc.ResolveRoute(ctx, agentlib.RouteRequest{
435				Model:    model,
436				Harness:  harnessName,
437				ModelRef: modelRef,
438				Provider: provider,
439			}); err != nil {
440				return fmt.Errorf("agent: model %q is not routable: %w", model, err)
441			}
442		}
443		return nil
444	}
