446	// ValidateEffortForRunViaService rejects effort requests that no currently
447	// available harness can satisfy. `ddx agent run` passes effort through to the
448	// service rather than resolving a route locally, but the command still needs a
449	// fast failure for obviously impossible combinations so operators get a useful
450	// error instead of a silent success path.
451	func ValidateEffortForRunViaService(ctx context.Context, workDir, profile, effort string) error {
452		if effort == "" {
453			return nil
454		}
455		if ctx == nil {
456			ctx = context.Background()
457		}
458		svc, err := NewServiceFromWorkDir(workDir)
459		if err != nil {
460			return fmt.Errorf("agent: build service: %w", err)
461		}
462		infos, err := svc.ListHarnesses(ctx)
463		if err != nil {
464			return fmt.Errorf("agent: list harnesses: %w", err)
465		}
466		registry := newHarnessRegistry()
467		for _, info := range infos {
468			if !info.Available {
469				continue
470			}
471			if harness, ok := registry.Get(info.Name); ok && harness.EffortFlag != "" {
472				return nil
473			}
474		}
475		if profile == "" {
476			return fmt.Errorf("agent: no selected provider candidate satisfies effort %q", effort)
477		}
478		return fmt.Errorf("agent: no selected provider candidate satisfies profile %q and effort %q", profile, effort)
479	}
